    public String renderUserProfile(String username, String templateContent) {
        // Validate inputs
        if (username == null) {
            throw new IllegalArgumentException("Username cannot be null");
        }
        if (templateContent == null) {
            throw new IllegalArgumentException("Template content cannot be null");
        }

        try {
            // Create unique template name to avoid collisions
            String templateName = "userProfile_" + System.nanoTime();

            // Load template into string loader
            StringTemplateLoader templateLoader = (StringTemplateLoader) configuration.getTemplateLoader();
            templateLoader.putTemplate(templateName, templateContent);

            // Get template (this re-reads from the loader)
            Template template = configuration.getTemplate(templateName);

            // Prepare data model with only the username variable
            Map<String, Object> dataModel = new HashMap<>();
            dataModel.put("username", escapeHtml(username));

            // Render template
            StringWriter writer = new StringWriter();
            template.process(dataModel, writer);

            // Clean up template from loader to prevent memory leak
            templateLoader.removeTemplate(templateName);

            return writer.toString();

        } catch (IOException | TemplateException e) {
            throw new TemplateProcessingException("Failed to render user profile template", e);
        }
    }

    /**
     * Escapes HTML special characters to prevent XSS attacks.
     * This provides defense-in-depth even with Freemarker's auto-escaping.
     */
    private String escapeHtml(String input) {
        if (input == null) {
            return null;
        }
        StringBuilder escaped = new StringBuilder();
        for (char c : input.toCharArray()) {
            switch (c) {
                case '<':
                    escaped.append("&lt;");
                    break;
                case '>':
                    escaped.append("&gt;");
                    break;
                case '&':
                    escaped.append("&amp;");
                    break;
                case '"':
                    escaped.append("&quot;");
                    break;
                case '\'':
                    escaped.append("&#x27;");
                    break;
                case '/':
                    escaped.append("&#x2F;");
                    break;
                default:
                    escaped.append(c);
            }
        }
        return escaped.toString();
    }

    /**
     * Custom exception for template processing errors.
     */
    public static class TemplateProcessingException extends RuntimeException {
        public TemplateProcessingException(String message, Throwable cause) {
            super(message, cause);
        }
    }
}
